import { HttpClient } from '@angular/common/http';
import { Injectable } from '@angular/core';
import { Observable } from 'rxjs';
import IUser from '../data-type/user';

@Injectable({
  providedIn: 'root',
})
export class UserService {
  constructor(private http: HttpClient) {}

  getUsers(): Observable<any> {
    console.log('user service');

    return this.http.get('../../assets/mock-data/users.json');
  }

  getUser(id: string): Observable<any> {
    let f = (observer) =>
      this.http
        .get('../../assets/mock-data/users.json')
        .subscribe((res: any) => {
          let users: IUser[] = res.data;
          let index: number = users.findIndex((item) => item.id === id);
          let user: IUser = users[index];
          observer.next(user);
        });

    return new Observable(f);
  }
}
